 1	import React, { FC } from 'react';
 2	import {
 3	  CHASSIS_ID,
 4	  NodeNetworkConfigurationInterfaceLLDPNeighbor,
 5	} from 'src/nmstate-types/custom-models/NodeNetworkConfigurationInterfaceLLDP';
 6	
 7	import { Stack, StackItem, Tooltip } from '@patternfly/react-core';
 8	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 9	import {
10	  getChassisId,
11	  getDescription,
12	  getIee8021Vlans,
13	  getPortId,
14	  getSystemDescription,
15	  getSystemName,
16	} from '@utils/neighbors/getters';
17	
18	const NeighborInformations: FC<{ neighbor: NodeNetworkConfigurationInterfaceLLDPNeighbor }> = ({
19	  neighbor,
20	}) => {
21	  const { t } = useNMStateTranslation();
22	
23	  const chassisIdDescription = getDescription(neighbor, CHASSIS_ID);
24	  const portId = getPortId(neighbor);
25	  const chassisId = getChassisId(neighbor);
26	  const systemName = getSystemName(neighbor);
27	  const systemDescription = getSystemDescription(neighbor);
28	  const iee8021Vlans = getIee8021Vlans(neighbor).sort((a, b) => a.vid - b.vid);
29	
30	  return (
31	    <Stack>
32	      {chassisId && (
33	        <StackItem>
34	          <strong>{chassisIdDescription}</strong>: {chassisId}
35	        </StackItem>
36	      )}
37	
38	      {portId && (
39	        <StackItem>
40	          <strong>{t('Port')}</strong>: {portId}
41	        </StackItem>
42	      )}
43	      {systemName && (
44	        <StackItem>
45	          <strong>{t('System Name')}</strong>: {systemName}
46	        </StackItem>
47	      )}
48	      {systemDescription && (
49	        <StackItem>
50	          <strong>{t('System Description')}</strong>: {systemDescription}
51	        </StackItem>
52	      )}
53	      {iee8021Vlans && (
54	        <StackItem>
55	          <strong>{t('VLANS')}</strong>:{' '}
56	          {iee8021Vlans?.map((vlan, index) => (
57	            <>
58	              <Tooltip content={vlan.name} key={vlan.vid}>
59	                <span>{vlan.vid}</span>
60	              </Tooltip>
61	              {index !== iee8021Vlans.length - 1 ? ', ' : ''}
62	            </>
63	          ))}
64	        </StackItem>
65	      )}
66	    </Stack>
67	  );
68	};
69	
70	export default NeighborInformations;

